'use client'

import { Navbar }        from '@/components/layout/Navbar'
import { FilterSidebar } from './components/FilterSidebar'
import { JobSections }   from './components/JobSections'

export default function JobsPage() {
  const trending = ['Product Designer', 'Frontend Engineer', 'Remote', 'AI / ML', 'Senior']

  return (
    <div className="min-h-screen bg-[#f7f3ef]">
      <Navbar />

      {/* ── HERO — horizontal split ──────────────────────────────────────── */}
      <div className="relative overflow-hidden border-b border-[#d4c4b5]">

        {/* Dot texture */}
        <div
          className="absolute inset-0 opacity-[0.03] pointer-events-none"
          style={{ backgroundImage: 'radial-gradient(#4a3728 1px, transparent 1px)', backgroundSize: '24px 24px' }}
        />
        {/* Blobs */}
        <div className="absolute top-[-60px] right-[-60px] w-72 h-72 rounded-full bg-[#e0d8cf] opacity-40 blur-3xl pointer-events-none" />
        <div className="absolute bottom-[-40px] left-[10%] w-56 h-56 rounded-full bg-[#d4c4b5] opacity-30 blur-3xl pointer-events-none" />

        <div className="relative max-w-7xl mx-auto px-6 py-14 grid grid-cols-2 gap-12 items-center">

          {/* ── LEFT: Heading + subtext + stats ── */}
          <div>
            {/* Eyebrow */}
            <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-[#4a3728]/[0.07] border border-[#4a3728]/10 mb-5">
              <span className="w-1.5 h-1.5 rounded-full bg-[#4a3728] animate-pulse" />
              <span className="text-[#4a3728] text-xs font-semibold tracking-wide">
                {new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' })} · New roles added daily
              </span>
            </div>

            {/* Heading */}
            <h1 className="text-[42px] font-black text-[#4a3728] leading-[1.1] tracking-tight">
              Find Your Next
              <br />
              <span className="relative inline-block mt-1">
                <span className="relative z-10">Opportunity.</span>
                <svg className="absolute -bottom-1 left-0 w-full" viewBox="0 0 300 12" fill="none" preserveAspectRatio="none">
                  <path d="M2 9 C60 3, 140 3, 298 8" stroke="#d4c4b5" strokeWidth="6" strokeLinecap="round" />
                </svg>
              </span>
            </h1>

            <p className="text-[#6b5847] text-base mt-4 leading-relaxed max-w-sm">
              Discover roles at the most ambitious companies — from seed-stage startups to category-defining giants.
            </p>

            {/* Stats */}
            <div className="mt-8 flex items-center gap-8 pt-6 border-t border-[#d4c4b5]/60">
              {[
                { number: '200+', label: 'Open Roles' },
                { number: '80+',  label: 'Companies'  },
                { number: '12k+', label: 'Applicants' },
              ].map(({ number, label }) => (
                <div key={label}>
                  <p className="text-2xl font-black text-[#4a3728]">{number}</p>
                  <p className="text-xs text-[#6b5847] font-medium mt-0.5">{label}</p>
                </div>
              ))}
            </div>
          </div>

          {/* ── RIGHT: Search card + trending badges ── */}
          <div className="flex flex-col gap-5">

            {/* Search card */}
            <div className="bg-white border border-[#d4c4b5] rounded-2xl p-5 shadow-sm flex flex-col gap-3">
              <p className="text-[#4a3728] text-sm font-bold">Search jobs</p>

              {/* Role input */}
              <div className="flex items-center gap-2.5 border border-[#d4c4b5] rounded-xl px-4 py-2.5 focus-within:border-[#4a3728]/40 transition-colors bg-[#f7f3ef]">
                <svg className="w-4 h-4 text-[#6b5847] shrink-0" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
                <input
                  type="text"
                  placeholder="Role, skill, or keyword..."
                  className="flex-1 bg-transparent text-[#4a3728] placeholder:text-[#6b5847]/40 text-sm font-medium outline-none"
                />
              </div>

              {/* Location input */}
              <div className="flex items-center gap-2.5 border border-[#d4c4b5] rounded-xl px-4 py-2.5 focus-within:border-[#4a3728]/40 transition-colors bg-[#f7f3ef]">
                <svg className="w-4 h-4 text-[#6b5847] shrink-0" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                  <path strokeLinecap="round" strokeLinejoin="round" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
                <input
                  type="text"
                  placeholder="City, state, or Remote..."
                  className="flex-1 bg-transparent text-[#4a3728] placeholder:text-[#6b5847]/40 text-sm font-medium outline-none"
                />
              </div>

              {/* Search button */}
              <button className="w-full py-2.5 bg-[#4a3728] hover:bg-[#3a2a1e] text-[#e0d8cf] text-sm font-bold rounded-xl transition-colors active:scale-[0.98] shadow-sm">
                Search Jobs
              </button>
            </div>

            {/* Trending badges */}
            <div>
              <p className="text-xs text-[#6b5847]/50 font-medium mb-2.5">Trending searches</p>
              <div className="flex flex-wrap gap-2">
                {trending.map(tag => (
                  <button
                    key={tag}
                    className="text-xs px-3 py-1.5 rounded-lg bg-white border border-[#d4c4b5] text-[#6b5847] hover:text-[#4a3728] hover:border-[#4a3728]/20 hover:bg-[#e0d8cf]/50 transition-colors font-medium shadow-sm"
                  >
                    {tag}
                  </button>
                ))}
              </div>
            </div>

          </div>
        </div>
      </div>

      {/* ── MAIN CONTENT ─────────────────────────────────────────────────── */}
      <main className="max-w-7xl mx-auto px-6 py-8">
        <div className="flex gap-6 items-start">
          <FilterSidebar />
          <div className="flex-1 min-w-0">
            <JobSections />
          </div>
        </div>
      </main>

    </div>
  )
}